package com.yottastudios.ns.collabspace.shared.mq;

import jakarta.annotation.Resource;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.core.MessageProperties;
import org.springframework.amqp.rabbit.core.RabbitTemplate;
import org.springframework.stereotype.Component;

@Component
public class RabbitMqSender {

    @Resource
    RabbitTemplate rabbitTemplate;

    public RabbitMqSender(RabbitTemplate rabbitTemplate) {
        this.rabbitTemplate = rabbitTemplate;
    }

    public void directSend(String exchangeName, String routeKey, Object object) {
        rabbitTemplate.convertAndSend(exchangeName, routeKey, object);

    }

    public void sendDelayedMessage(String exchangeName, String routeKey, Object object, long delayMillis) {
        rabbitTemplate.convertAndSend(
                exchangeName, routeKey, object,
                m -> {
                    m.getMessageProperties().setHeader("x-delay", delayMillis); // 设置延迟时间（毫秒）
                    return m;
                }
        );
    }
}

