package com.yottastudios.ns.collabspace.starter.socketio.autoconfigure;

import com.yottastudios.ns.collabspace.starter.socketio.core.MyWebSocketInterceptor;
import com.yottastudios.ns.collabspace.starter.socketio.core.SocketClientTemplate;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.boot.context.properties.EnableConfigurationProperties;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.stereotype.Component;
import org.springframework.web.socket.TextMessage;
import org.springframework.web.socket.WebSocketSession;
import org.springframework.web.socket.config.annotation.EnableWebSocket;
import org.springframework.web.socket.config.annotation.WebSocketConfigurer;
import org.springframework.web.socket.config.annotation.WebSocketHandlerRegistry;
import org.springframework.web.socket.handler.TextWebSocketHandler;
import org.springframework.web.socket.server.standard.ServerEndpointExporter;

@Configuration
@EnableWebSocket
@Slf4j
@Component
@EnableConfigurationProperties(SocketioProperties.class)
public class WebSocketConfig implements WebSocketConfigurer {
    @Autowired
    private SocketioProperties socketioProperties;
    @Autowired
    private WebSocketHandler webSocketHandler;


    /**
     * 注册WebSocket处理器
     */
    @Override
    public void registerWebSocketHandlers(WebSocketHandlerRegistry registry) {
        log.info("开始注册WebSocket处理器");
        log.info("配置属性 - enabled: {}", socketioProperties.getServer().isEnabled());
        log.info("配置属性 - path: {}", socketioProperties.getServer().getPath());
        if (socketioProperties.getServer() != null && socketioProperties.getServer().isEnabled()) {
            String path = socketioProperties.getServer().getPath();

            WebSocketHandler handler = getMyWebSocketHandler();
            MyWebSocketInterceptor interceptor = getMyWebSocketInterceptor();

            log.info("注册Handler: {}", handler.getClass().getName());
            log.info("注册Interceptor: {}", interceptor.getClass().getName());
            log.info("注册路径: {}", path);

            registry.addHandler(handler, path)
                    .addInterceptors(interceptor)
                    .setAllowedOrigins(socketioProperties.getServer().getAllowedOrigins());

            log.info("WebSocket处理器注册完成！");
        }
    }

    @Bean
    public WebSocketHandler getMyWebSocketHandler(){
        return new WebSocketHandler();
    }

    @Bean
    public MyWebSocketInterceptor getMyWebSocketInterceptor(){
        return new MyWebSocketInterceptor();
    }

    @Bean
    public ServerEndpointExporter serverEndpointExporter() {
        // 该 Bean 会自动注册使用 @ServerEndpoint 注解申明的 websocket endpoint
        return new ServerEndpointExporter();
    }


}

