package com.yottastudios.ns.collabspace.starter.socketio.core;

import cn.hutool.core.util.IdUtil;
import cn.hutool.json.JSONObject;
import cn.hutool.json.JSONUtil;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.yottastudios.ns.collabspace.starter.socketio.core.SocketClientTemplate;
import jakarta.annotation.Resource;
import lombok.Getter;
import lombok.extern.slf4j.Slf4j;
import org.checkerframework.checker.units.qual.A;
import org.checkerframework.checker.units.qual.C;
import org.jetbrains.annotations.NotNull;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.data.redis.core.RedisTemplate;
import org.springframework.stereotype.Component;
import org.springframework.util.CollectionUtils;
import org.springframework.web.*;
import org.springframework.web.socket.CloseStatus;
import org.springframework.web.socket.TextMessage;
import org.springframework.web.socket.WebSocketMessage;
import org.springframework.web.socket.WebSocketSession;
import org.springframework.web.socket.handler.TextWebSocketHandler;

import java.io.IOException;
import java.net.URI;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

/**
 * 混合WebSocket处理器
 * 结合TextWebSocketHandler和SocketIO客户端功能
 */
@Slf4j
@Component
public class WebSocketHandler extends TextWebSocketHandler {


    @Resource
    private RedisTemplate<String, Object> redisTemplate;


    private final TextMessage heart = new TextMessage("ru");


    private static final ConcurrentHashMap<String, WSUserModel> USER_SOCKET_SESSION_MAP;


    static {
        USER_SOCKET_SESSION_MAP = new ConcurrentHashMap<String, WSUserModel>(12);
    }

    public Map<String, WSUserModel> getCurrentUserMap() {
        return Collections.unmodifiableMap(USER_SOCKET_SESSION_MAP);
    }


    /**
     * 前台连接并且注册了账户
     */
    @Override
    public void afterConnectionEstablished(WebSocketSession session) throws Exception {
        log.info("afterConnectionEstablished");

        session.setTextMessageSizeLimit(50 * 1024); // 消息大小设置为50KB 不够用再扩展
        session.setBinaryMessageSizeLimit(50 * 1024);
        openConn(session);
    }

    /**
     * 接受消息
     *
     * @param session
     * @param message
     * @throws Exception
     */
    @Override
    public void handleMessage(WebSocketSession session, WebSocketMessage<?> message) throws Exception {
        String messageContent = message.getPayload().toString();
        log.debug("收到消息: {}", messageContent);


        // 处理心跳消息
        if ("pong".equals(messageContent) || "ping".equals(messageContent)) {
            handleHeartbeatMessage(session, messageContent);
            return;
        }
        // 处理其他业务消息
        try {
            JSONObject messageObj = JSONUtil.parseObj(messageContent);
            String type = messageObj.getStr("type");

            if ("heartbeat".equals(type)) {
                handleHeartbeatMessage(session, "pong");
            }
        } catch (Exception e) {
            log.error("处理消息失败: {}", e.getMessage(), e);
        }
    }


    /**
     * 处理心跳消息
     */
    private void handleHeartbeatMessage(WebSocketSession session, String messageContent) {
        try {
            if ("ping".equals(messageContent)) {
                // 客户端发来ping，回复pong
                session.sendMessage(new TextMessage("pong"));
                log.debug("收到ping，回复pong: {}", session.getId());
            } else if ("pong".equals(messageContent)) {
                // 客户端回复pong，记录心跳时间
                log.debug("收到pong响应: {}", session.getId());
            }
        } catch (IOException e) {
            log.error("发送心跳响应失败: {}", e.getMessage(), e);
        }
    }


    /**
     * 消息传输错误处理，如果出现错误直接断开连接
     */
    @Override
    public void handleTransportError(WebSocketSession session, Throwable exception) throws Exception {
        log.warn("handleTransportError:{};exception:{}", session, exception);
        if (session.isOpen()) {
            session.close();
        }
        closeConn(session, true);
    }

    /**
     * 关闭连接后
     */
    @Override
    public void afterConnectionClosed(WebSocketSession session, CloseStatus closeStatus) throws Exception {
        closeConn(session, false);
    }

    @Override
    public boolean supportsPartialMessages() {
        return false;
    }


    public void sendAllUserToWebSocketClient(String message) {
        int sendCount = sendToMatchedSockets(message, null, null);
        log.info("sendAllUserToWebSocketClient - 实际发送数: {}", sendCount);
    }

    /**
     * 给指定用户列表发送消息（覆盖用户的全部在线端）
     *
     * @param message 消息内容
     * @param userIds 目标用户id集合
     * @return 实际发送成功的连接数
     */
    public int sendUsersToWebSocketClient(String message, Collection<Long> userIds) {
        if (CollectionUtils.isEmpty(userIds)) {
            return 0;
        }
        Set<Long> targetUserIds = new HashSet<Long>(userIds);
        return sendToMatchedSockets(message, targetUserIds, null);
    }

    /**
     * 给单个用户发送消息（覆盖该用户全部在线端）
     *
     * @param message 消息内容
     * @param userId 目标用户id
     * @return 实际发送成功的连接数
     */
    public int sendUserToWebSocketClient(String message, Long userId) {
        if (userId == null) {
            return 0;
        }
        return sendUsersToWebSocketClient(message, Collections.singleton(userId));
    }

    /**
     * 给指定socketKey集合发送消息（socketKey格式：userId-customId）
     *
     * @param message 消息内容
     * @param socketKeys 目标socketKey集合
     * @return 实际发送成功的连接数
     */
    public int sendSocketKeysToWebSocketClient(String message, Collection<String> socketKeys) {
        if (CollectionUtils.isEmpty(socketKeys)) {
            return 0;
        }
        Set<String> targetSocketKeys = new HashSet<String>(socketKeys);
        return sendToMatchedSockets(message, null, targetSocketKeys);
    }

    private int sendToMatchedSockets(String message, Set<Long> targetUserIds, Set<String> targetSocketKeys) {
        int sendCount = 0;
        TextMessage textMessage = new TextMessage(message);
        for (Map.Entry<String, WSUserModel> entry : USER_SOCKET_SESSION_MAP.entrySet()) {
            String socketKey = entry.getKey();
            WSUserModel wsUserModel = entry.getValue();
            if (!isMatchedSocket(socketKey, wsUserModel, targetUserIds, targetSocketKeys)) {
                continue;
            }
            WebSocketSession session = wsUserModel.getWs();
            if (session == null || !session.isOpen()) {
                USER_SOCKET_SESSION_MAP.remove(socketKey);
                continue;
            }
            try {
                synchronized (session) {
                    session.sendMessage(textMessage);
                }
                sendCount++;
            } catch (IOException e) {
                log.error("向WebSocket客户端发送消息失败 - 用户: {}, 错误: {}", socketKey, e.getMessage());
                USER_SOCKET_SESSION_MAP.remove(socketKey);
            }
        }
        return sendCount;
    }

    private boolean isMatchedSocket(String socketKey, WSUserModel wsUserModel,
                                    Set<Long> targetUserIds, Set<String> targetSocketKeys) {
        boolean matchedByUser = CollectionUtils.isEmpty(targetUserIds);
        if (!matchedByUser) {
            Long userId = wsUserModel.getUserId();
            matchedByUser = userId != null && targetUserIds.contains(userId);
        }
        if (!matchedByUser) {
            return false;
        }
        return CollectionUtils.isEmpty(targetSocketKeys) || targetSocketKeys.contains(socketKey);
    }


    /**
     * 给单个用户发消息
     *
     * @param session
     * @param message
     */
    private static void sendMessageWs(WebSocketSession session, WebSocketMessage message) {
        try {
//            log.info("sendMessageToUser--WebSocketSession");
            synchronized (session) {
                session.sendMessage(message);
            }
        } catch (Exception ex) {
            log.warn(ex.toString() + ";WebSocketSession:" + session + "message" + message);
        }
    }


    /**
     * 给某个文档下所有有权限读的人发消息
     *
     * @param session
     * @param message
     */
    private static void sendFileMessageWs(WebSocketSession session, WebSocketMessage message) {
        // todo:暂时不实现，待增加缓存权限后实现，目前更新文档采用的方式是向全部的在线用户发消息，由前端判断这条消息的显示/丢弃

    }

    /**
     * 给所有在线的用户发消息
     */
//    private static void sendMessageToAllUser(ConcurrentHashMap<String, WSUserModel> userMap, String content) {
//        if (userMap != null && content != null) {
//            TextMessage message = new TextMessage(content);
//            userMap.forEach((k, v) -> {
//                // 给当前文档的所有用户发送消息
//                sendMessageWs(v.getWs(), message);
//            });
//        }
//    }
    private static void sendMessageToWs(WebSocketSession session, String message) {

//        log.info("sendMessageToUser--onlyForUser");
        sendMessageWs(session, new TextMessage(message));
    }


    /**
     * 当有用户连接时，把用户添加到USER_SOCKET_SESSION_MAP里，并且返回给前端连接成功
     *
     * @param session
     */
    private void openConn(WebSocketSession session) {
        //创建一个连接窗口，并加入的队列中
        WSUserModel ws = new WSUserModel(session);
        WSUserModel.webSocketMapAdd(USER_SOCKET_SESSION_MAP, ws);
        log.info("有新窗口开始监听 wsId:{}, gridKey:{}", ws.getId(), ws.getGridKey());
        try {
            WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.success(MessageTypeEnum.CONNECT_SUCCESS.getDesc(), null);
            ObjectMapper obj = new ObjectMapper();
            String params = obj.writeValueAsString(webSocketResponseModel);
            sendMessageToWs(session, params);

        } catch (Exception e) {
            log.error("openConn--Exception:" + e);
        }
    }


    private void closeConn(WebSocketSession session, boolean isError) {
        WSUserModel wsUserModel = new WSUserModel(session);
        WSUserModel.webSocketMapRemove(USER_SOCKET_SESSION_MAP, wsUserModel);

        if (isError) {
            log.info("窗口关闭(Error) wsId:{}, gridKey:{}", wsUserModel.getId(), wsUserModel.getGridKey());
        } else {
            log.info("窗口关闭 wsId:{}, gridKey:{}", wsUserModel.getId(), wsUserModel.getGridKey());
            try {
                WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.success(MessageTypeEnum.CONNECT_CLOSE.getDesc(), null);
                ObjectMapper obj = new ObjectMapper();
                String params = obj.writeValueAsString(webSocketResponseModel);
                sendMessageToWs(session, params);
            } catch (Exception ex) {
                log.error("closeConn--Exception:" + ex);
            }
        }

    }
}

