// 一键反馈 组件
import { useKeyPress } from 'ahooks';
import { Checkbox, Form, Input, Modal, type UploadFile } from 'antd';
import dayjs from 'dayjs';
import { memo, useMemo, useState } from 'react';

import { localFeedbackButtonOffset } from '@/common/localVar';
import { antdApp } from '@/common/pageInit.tsx';
import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
import { CustomUpload } from '@/components/CustomUpload/CustomUpload.tsx';
import { EdgeSnapButton } from '@/components/EdgeSnapButton/EdgeSnapButton.tsx';
import { useStateLocal } from '@/hooks/useStateLocal.ts';
import { t } from '@/i18n';
import { FeedbackFill } from '@/icon';
import { useRootSelector } from '@/store';
import { getCurrUser } from '@/store/system.ts';
import { captureMessage } from '@/utils/sentry.ts';

type IFormData = {
  nickName?: string;
  href?: string;
  types?: string[];
  desc?: string;
  files?: UploadFile[];
};

export const FeedbackSubmissionBase = () => {
  const me = useRootSelector(getCurrUser);
  useKeyPress('ctrl.shift.h', () => {
    setOpen(true);
  });
  const types = useMemo(() => {
    return [
      {
        label: <I18nText>feedbackTypeLag</I18nText>,
        value: 'lag',
      },
      {
        label: <I18nText>feedbackTypeBug</I18nText>,
        value: 'bug',
      },
      {
        label: <I18nText>feedbackTypeFeature</I18nText>,
        value: 'feat',
      },
      {
        label: <I18nText>feedbackTypeOther</I18nText>,
        value: 'other',
      },
    ];
  }, []);
  const [offset, setOffset] = useStateLocal(localFeedbackButtonOffset.get, localFeedbackButtonOffset.set);
  const [open, setOpen] = useState(false);
  const [form] = Form.useForm<IFormData>();
  const onConfirm = () => {
    form.validateFields().then(() => {
      const data = form.getFieldsValue();
      captureMessage(`${me.nickName}: submitted feedback in ${dayjs().format('YYYY-MM-DD HH:mm')}`, 'info', {
        desc: data.desc,
        types: data.types?.toString(),
        // eslint-disable-next-line @typescript-eslint/no-shadow
      }, data.types?.map((t) => {
        return {
          key: `feedback-${t}`,
          value: 'true',
        };
      }), data.files?.map((o) => o.originFileObj as File));
      antdApp.message.success(<I18nText>feedbackSuccess</I18nText>);
      setOpen(false);
    });
  };
  return (
    <>
      <Modal
        open={open}
        onCancel={() => {
          setOpen(false);
        }}
        destroyOnHidden
        width={550}
        title={(
          <span>
            <I18nText>feedbackQuick</I18nText>
            <span
              className="text-sm font-normal ml-2 cursor-pointer"
              onClick={() => {
                setOffset([0, 0]);
              }}
            >
              <span className="text-color-text-description">
                <I18nText>cannotFindFeedbackBtn</I18nText>
              </span>

              <span className="text-primary">
                <I18nText>clickMeToRestFeedbackBtn</I18nText>
              </span>
            </span>

          </span>
        )}
        onOk={onConfirm}

      >
        <Form
          form={form}
          labelCol={{ className: 'w-[90px]' }}
          labelWrap
          colon={false}
        >
          <Form.Item
            rules={[
              {
                required: true,
                type: 'string',
              },
            ]}
            name="nickName"
            label={<I18nText>feedbackUser</I18nText>}
          >
            <Input disabled />
          </Form.Item>
          <Form.Item
            name="href"
            rules={[
              {
                required: true,
                type: 'string',
              },
            ]}
            label={<I18nText>feedbackPageLink</I18nText>}
          >
            <Input disabled />
          </Form.Item>
          <Form.Item
            name="types"
            rules={[
              {
                required: true,
                type: 'array',
                message: <I18nText>feedbackTypeHint</I18nText>,
              },
            ]}
            label={<I18nText>feedbackType</I18nText>}
          >
            <Checkbox.Group options={types} />
          </Form.Item>
          <Form.Item name="desc" label={<I18nText>feedbackAdditionalInfo</I18nText>}>
            <Input.TextArea rows={9} />
          </Form.Item>
          <Form.Item name="files" label={<I18nText>attachment</I18nText>}>
            <CustomUpload ctrlV className="max-h-[200px] overflow-auto" />
          </Form.Item>

        </Form>
      </Modal>
      <EdgeSnapButton
        onOffsetChange={setOffset}
        offset={offset}
        className="p-[4px] bg-primary-bg text-color-text select-none right-0 top-16"
        onClick={() => {
          setOpen(true);
          form.setFieldsValue({
            nickName: me.nickName,
            href: window.location.href,
            types: ['feat'],
            desc: '',
            files: [],
          });
        }}
      >
        <span title={t('feedbackQuick')} className="bg-primary flex items-center justify-center p-2 rounded-full">
          <FeedbackFill className="text-gray-50 text-[14px]" />
        </span>
      </EdgeSnapButton>
    </>

  );
};
export const FeedbackSubmission = memo(FeedbackSubmissionBase);

