package com.yottastudios.ns.collabspace.third.feign;

import com.yottastudios.ns.collabspace.third.req.MattermostPostReq;
import com.yottastudios.ns.collabspace.third.resp.MattermostDirectChannelResp;
import com.yottastudios.ns.collabspace.third.resp.MattermostFileUploadResp;
import com.yottastudios.ns.collabspace.third.resp.MattermostPostResp;
import com.yottastudios.ns.collabspace.third.resp.MattermostUserInfoResp;
import org.springframework.cloud.openfeign.FeignClient;
import org.springframework.web.bind.annotation.*;

import java.util.List;

@FeignClient(name = "mattermostMessageService", url = "${auth.mattermost-url}")
public interface MattermostMessageFeign {

    @PostMapping(value = "/api/v4/posts", consumes = "application/json")
    MattermostPostResp createPost(
            @RequestHeader("Authorization") String authorization,
            @RequestParam(value = "set_online", required = false) Boolean setOnline,
            @RequestBody MattermostPostReq postReq
    );

    @PostMapping(value = "/api/v4/files", consumes = "application/octet-stream")
    MattermostFileUploadResp uploadFileWithQueryParam(
            @RequestHeader("Authorization") String authorization,
            @RequestParam("channel_id") String channelId,
            @RequestParam("filename") String filename,
            @RequestBody byte[] file
    );

    @GetMapping(value = "/api/v4/users/email/{email}", produces = "application/json")
    MattermostUserInfoResp getUserByEmail(
            @RequestHeader("Authorization") String authorization,
            @PathVariable("email") String email
    );

    @PostMapping(value = "/api/v4/channels/direct", consumes = "application/json")
    MattermostDirectChannelResp createDirectMessageChannel(
            @RequestHeader("Authorization") String authorization,
            @RequestBody List<String> userIds
    );
}

