package com.yottastudios.ns.collabspace.space.service.impl;

import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.List;

/**
 * 空间站申请 knock/mm 通知服务.
 * 向空间站管理员发送申请加入消息（通过 apitable gRPC 调用 knock/mm）.
 */
@Slf4j
@Service
public class WorkspaceApplyNotifyService {

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    /**
     * 向空间站管理员发送申请加入通知.
     * 通过 apitable gRPC 向各管理员发送 knock/mm 消息.
     *
     * @param workspaceId  空间站 ID
     * @param spaceName    空间站名称
     * @param adminUserIds 管理员用户 ID 列表
     * @param message      消息内容
     */
    public void notifyAdmins(String workspaceId, String spaceName,
                             List<Long> adminUserIds, String message) {
        log.info("[1822-WorkspaceApply] notifyAdmins start workspaceId={} spaceName={} adminCount={}",
                workspaceId, spaceName, adminUserIds != null ? adminUserIds.size() : 0);

        if (adminUserIds == null || adminUserIds.isEmpty()) {
            log.warn("[1822-WorkspaceApply] notifyAdmins empty workspaceId={}", workspaceId);
            return;
        }

        try {
            apitableGrpcClientService.sendWorkspaceApplyNotify(adminUserIds, message);
            log.info("[1822-WorkspaceApply] notifyAdmins SUCCESS workspaceId={} adminCount={}", workspaceId, adminUserIds.size());
        } catch (Exception e) {
            log.error("[1822-WorkspaceApply] ERROR notifyAdmins workspaceId={} error={}", workspaceId, e.getMessage(), e);
        }
    }
}

