package com.yottastudios.ns.collabspace.announcement.service.impl;

import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementEntity;
import com.yottastudios.ns.collabspace.announcement.util.AnnouncementFormatConverter;
import com.yottastudios.ns.collabspace.grpc.IApitableGrpcClientService;
import com.yottastudios.ns.collabspace.shared.config.properties.MattermostProperties;
import com.yottastudios.ns.collabspace.third.feign.MattermostMessageFeign;
import com.yottastudios.ns.collabspace.third.req.MattermostPostReq;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

/**
 * 公告发布后同步推送到 Knock 和 MM
 */
@Slf4j
@Service
public class AnnouncementPushService {

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private MattermostMessageFeign mattermostMessageFeign;

    @Resource
    private MattermostProperties mattermostProperties;

    /**
     * 公告发布后推送到 Knock + MM
     */
    public void pushAnnouncement(AnnouncementEntity announcement) {
        log.info("[lbl][2087-消息推送][Announcement][PUSH] 开始推送公告到Knock+MM, id={}, title={}", announcement.getId(), announcement.getTitle());

        pushToKnock(announcement);
        pushToMm(announcement);

        log.info("[lbl][2087-消息推送][Announcement][PUSH] 公告推送完成, id={}", announcement.getId());
    }

    /**
     * 推送到 Knock（通过 gRPC）
     */
    private void pushToKnock(AnnouncementEntity announcement) {
        try {
            String knockContent = AnnouncementFormatConverter.toKnockMarkdown(announcement.getContent());
            // 使用已有的 gRPC 通知接口全量推送
            apitableGrpcClientService.createExternalNotify(
                    null, // 全量推送，toUserIds 为 null
                    null, // spaceId
                    "announcement_push", // templateId
                    String.valueOf(announcement.getCreatorId()),
                    knockContent,
                    null, // nodeId
                    "collabspace"
            );
            log.info("[lbl][2087-消息推送][Announcement][PUSH] Knock推送成功, id={}", announcement.getId());
        } catch (Exception e) {
            log.error("[lbl][2087-消息推送][Announcement][PUSH] Knock推送失败, id={}, error={}", announcement.getId(), e.getMessage(), e);
        }
    }

    /**
     * 推送到 MM（通过 Feign 调用 XCollabSpace 机器人）
     */
    private void pushToMm(AnnouncementEntity announcement) {
        try {
            String mmContent = AnnouncementFormatConverter.toMmMarkdown(announcement.getContent());
            // 拼接标题
            String fullMessage = "## " + announcement.getTitle() + "\n\n" + mmContent;

            String authToken = "Bearer " + mattermostProperties.getXcollabspaceBotToken();
            String channelId = mattermostProperties.getXcollabspaceChannelId();

            MattermostPostReq postReq = MattermostPostReq.builder()
                    .channelId(channelId)
                    .message(fullMessage)
                    .build();

            mattermostMessageFeign.createPost(authToken, false, postReq);
            log.info("[2087-Push] pushToMm SUCCESS id={}", announcement.getId());
        } catch (Exception e) {
            log.error("[2087-Push] pushToMm FAIL id={} error={}", announcement.getId(), e.getMessage(), e);
        }
    }
}

package com.yottastudios.ns.collabspace.announcement.consumer;

import cn.hutool.json.JSONUtil;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.rabbitmq.client.Channel;
import com.yottastudios.ns.collabspace.announcement.entity.AnnouncementEntity;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementStatus;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementType;
import com.yottastudios.ns.collabspace.announcement.mapper.AnnouncementMapper;
import com.yottastudios.ns.collabspace.announcement.service.impl.AnnouncementPushService;
import com.yottastudios.ns.collabspace.starter.socketio.core.MessageTypeEnum;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketResponseModel;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.amqp.core.Message;
import org.springframework.amqp.rabbit.annotation.RabbitListener;
import org.springframework.stereotype.Component;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;

import java.io.IOException;
import java.time.LocalDateTime;

import static com.yottastudios.ns.collabspace.shared.config.QueueConfig.ANNOUNCEMENT_QUEUE;

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class AnnouncementConsumer {
    @Resource
    AnnouncementMapper announcementMapper;

    @Resource
    WebSocketHandler webSocketHandler;

    @Resource
    AnnouncementPushService announcementPushService;

    @RabbitListener(queues = ANNOUNCEMENT_QUEUE)
    public void handle(Message message, Channel channel) throws IOException {
        log.info("Received announcement message: {}", message);
        String body = new String(message.getBody());
        Long announcementId = Long.parseLong(body);
        try {
        AnnouncementEntity announce = announcementMapper.selectById(announcementId);
        if (announce == null || announce.getStatus() == AnnouncementStatus.CANCELLED.getCode()
        || announce.getType() == AnnouncementType.DRAFT.getCode()) {
            throw new RuntimeException("公告不需要发布");
        }
        announce.setStatus(AnnouncementStatus.PUBLISHED.getCode());
        announce.setUpdatedAt(LocalDateTime.now());
        announcementMapper.updateById(announce);

         WebSocketResponseModel webSocketResponseModel = WebSocketResponseModel.builder().type(MessageTypeEnum.ADD_ANNOUNCEMENT.getType())
                    .message("更新公告").status(200).data(null).build();
         String msg = JSONUtil.toJsonStr(webSocketResponseModel);
         webSocketHandler.sendAllUserToWebSocketClient(msg);

         // 同步推送到 Knock + MM
         announcementPushService.pushAnnouncement(announce);
        } catch (Exception e) {
            log.error("Failed to publish timed announcement, id={}", announcementId);
        } finally {
            // 先不考虑重试
            long deliveryTag = message.getMessageProperties().getDeliveryTag();
            channel.basicAck(deliveryTag, false);
        }
    }
}

