async function testWriteAndVerify() {
  console.log('\n⚡ 写操作验证');

  // 1. 读取原始状态
  const before = await GET('/listXxx?pageNo=1&pageSize=1');
  const original = before.data?.records?.[0];
  if (!original) { console.log('  ⚠️ 无数据，跳过'); return; }
