import com.yottastudios.ns.collabspace.third.req.CreateFileReq;
import com.yottastudios.ns.collabspace.user.vo.UserSimpleInfoVo;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeQueryManager;
import com.yottastudios.ns.collabspace.workspace.vo.ExportLuckysheetResult;
import com.yottastudios.ns.collabspace.third.feign.NextcloudService;
import com.yottastudios.ns.collabspace.third.feign.OnlyofficeService;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.lang3.StringUtils;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import java.io.IOException;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

import com.yottastudios.ns.collabspace.interfaces.eventbus.facade.EventBusFacade;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.TestEvent;

@Slf4j
@RestController
@Tag(name = "test")
@ApiResource(path = "/test")
public class TestController {

    @Resource
    private TreeNodeTemplate treeNodeTemplate;

    @Resource
    private ControlTemplate controlTemplate;

    @Resource
    private ISpaceService spaceService;

    @Resource
    private ISpaceAppRelService spaceAppRelService;

    @Resource
    private AffineHttpClientService affineHttpClientService;

    @Resource
    private ConstProperties constProperties;

    @Resource
    private OnlyofficeService onlyofficeService;

    @Resource
    private IApitableGrpcClientService apitableGrpcClientService;

    @Resource
    private SpaceNodeQueryManager spaceNodeQueryManager;

    @Resource
    private EventBusFacade eventBusFacade;

    @Resource
    private NextcloudService nextcloudService;

    @PostResource(path = "/parentNodeTreeTest", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "Get Parent Node Tree for test")
    public ResponseData<List<NodeTreeVo>> getParentNodeTree(@RequestBody @Valid List<Long> relIds) {
        List<NodeEntity> nodes = treeNodeTemplate.getParentPathNodesByRelIds(relIds);
        List<NodeTreeVo> nodeTreeVos = nodes.stream()
                .map(item -> new NodeTreeVo(item, null)).toList();
        return ResponseData.success(TreeUtil.build(nodeTreeVos));
    }

    @PostResource(path = "/control", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "Get control test")
    public ResponseData<ControlRoleDict> getControl(@RequestBody ControlRequestTestRo ro) {
        Long userId = resolveUserId(ro);
        return ResponseData.success(controlTemplate.fetchSpaceNodeRole(userId, ro.spaceNodeIds()));
    }

    @PostResource(path = "/controlSpaceNodeRoleCacheQuery", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "Get control by legacy cache query mode")
    public ResponseData<ControlRoleDict> getControlByCacheQuery(@RequestBody ControlRequestTestRo ro) {
        Long userId = resolveUserId(ro);
        return ResponseData.success(controlTemplate.fetchSpaceNodeRoleCached(userId, ro.spaceNodeIds()));
    }

    @PostResource(path = "/controlSpaceNodeRoleExecuteWithCache", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "Get control by executeWithCache mode")
    public ResponseData<ControlRoleDict> getControlByExecuteWithCache(@RequestBody ControlRequestTestRo ro) {
        Long userId = resolveUserId(ro);
        return ResponseData.success(controlTemplate.fetchSpaceNodeRoleExecuteWithCache(userId, ro.spaceNodeIds()));
    }

    @PostResource(path = "/controlIn", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "Get control internal test")
    public ResponseData<ControlRoleDict> getControlIn(@RequestBody ControlRequestTestRo ro) {
        Long userId = resolveUserId(ro);
        return ResponseData.success(controlTemplate.fetchInternalNodeRole(userId, ro.spaceNodeIds()));
    }

    public record ControlRequestTestRo(Long userId, String email, List<Long> spaceNodeIds) { }

    private Long resolveUserId(ControlRequestTestRo ro) {
        if (StringUtils.isNoneBlank(ro.email())) {
            return apitableGrpcClientService.getUserByEmail(ro.email()).getId();
        }
        return ro.userId();
    }


    @PostResource(path = "/spaceByName", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "Get spaceByName for developer")
    public ResponseData<List<SpaceEntity>> getSpaceByName(@RequestBody SpaceByName ro) {
        String name = ro.name;
        return ResponseData.success(spaceService.listByName(name));
    }
    public record SpaceByName(String name) { }

    @PostResource(path = "/spaceTreeById", requiredPermission = false)
    @Operation(summary = "Get spaceTreeById for developer")
    public ResponseData<List<TreeNode<SpaceNodeVo>>> getSpaceTreeById(@RequestBody SpaceId ro) {
        String id = ro.id;
        return ResponseData.success(spaceNodeQueryManager.getSpaceNodeTreeWithoutRole(id));
    }
    public record SpaceId(String id) { }

    @GetResource(path = "/testLogin/{spaceId}/{nodeId}/{userId}", requiredPermission = false)
    @Operation(summary = "测试服email登录")
    public void testLogin(@PathVariable final String spaceId, @PathVariable String nodeId,@PathVariable Long userId) throws IOException {
        apitableGrpcClientService.deleteNodeTotally(userId,spaceId,nodeId);
    }

    @GetResource(path = "/testConst", requiredPermission = false)
    @Operation(summary = "测试服email登录")
    public ResponseData<String> testConst() {
        return ResponseData.success(constProperties.getProjectEnv());
    }

    @GetResource(path = "/syncSpaceApp", requiredPermission = false)
    @Operation(summary = "刷一遍子应用空间站")
    public void syncSpaceApp() {

        List<SpaceEntity> spaces = spaceService.list();

        //刷用户
        Set<Long> userIds = spaces.stream()
                .flatMap(space -> {
                    Set<Long> ids = new HashSet<>();
                    if (space.getOwner() != null) {
                        ids.add(space.getOwner());
                    }
                    if (space.getCreatedBy() != null) {
                        ids.add(space.getCreatedBy());
                    }
                    if (space.getUpdatedBy() != null) {
                        ids.add(space.getUpdatedBy());
                    }
                    return ids.stream();
                })
                .collect(Collectors.toSet());

        for (Long userId : userIds) {
            UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
            CreateUserResponse res = affineHttpClientService.createUser(new CreateUserRequest(user.getEmail(), user.getNickName(), "dev"), 1861372503096078339L);// 1861372503096078339测试服的test用户
            log.info("create affine user , email: {}, name: {}, response: {}", user.getEmail(), user.getNickName(), res);
        }

        //刷空间站
        for (SpaceEntity space : spaces) {
            List<SpaceAppRelEntity> spaceAppRelEntities = spaceAppRelService.listBySpaceId(space.getSpaceId());
            Set<Integer> appTypeSet = spaceAppRelEntities.stream().map(SpaceAppRelEntity::getAppType).collect(Collectors.toSet());
            if(!appTypeSet.contains(SpaceAppTypeEnum.AFFINE.getValue())) {
                String afResult = affineHttpClientService.createWorkspace(new CreateWorkspaceRequest(space.getName(),"aio"), space.getOwner());
                log.info("affine workspace {} created by user: {} , result: {}", space.getName(), space.getOwner(), afResult);
                SpaceAppRelEntity entity = SpaceAppRelEntity.builder()
                        .spaceId(space.getSpaceId())
                        .appSpaceId(afResult)
                        .appType(SpaceAppTypeEnum.AFFINE.getValue())
                        .createdAt(space.getCreatedAt())
                        .createdBy(space.getCreatedBy())
                        .build();
                spaceAppRelService.save(entity);
            }
        }

    }

    @GetResource(path = "/testOnlyofficeCreateFile", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "测试 ONLYOFFICE 创建文件接口")
    public ResponseData<String> testOnlyofficeCreateFile() {
        try {
            String fileId = onlyofficeService.createFile(new CreateFileReq());
            return ResponseData.success(fileId);
        } catch (Exception e) {
            log.error("ONLYOFFICE 创建文件失败: {}", e.getMessage());
            return ResponseData.status(false, 500, "创建文件失败: " + e.getMessage()).data(null);
        }
    }

    @GetResource(path = "/testExportLuckysheet/{nodeId}", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "测试导出 Luckysheet 到 Minio")
    public ResponseData<ExportLuckysheetResult> testExportLuckysheetToMinio(@PathVariable String nodeId) {
        try {
            ExportLuckysheetResult result = apitableGrpcClientService.exportLuckysheetToMinio(nodeId);
            log.info("导出 Luckysheet 节点 {} 成功: {}", nodeId, result);
            return ResponseData.success(result);
        } catch (Exception e) {
            log.error("导出 Luckysheet 节点 {} 失败: {}", nodeId, e.getMessage());
            return ResponseData.status(false, 500, "导出失败: " + e.getMessage()).data(null);
        }
    }

    @GetResource(path = "/sendTestEvent/{payload}", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "触发 TestEvent")
    public ResponseData<String> sendTestEvent(@PathVariable String payload) {
        eventBusFacade.onEvent(new TestEvent(payload));
        return ResponseData.success("ok");
    }

    @GetResource(path = "/ncFilePathByFileId", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "通过 fileId 查询 Nextcloud 文件路径")
    public ResponseData<String> getFilePathByFileId(String fileId, String spaceName) {
        String path = nextcloudService.getFilePathByFileId(fileId, spaceName);
        return ResponseData.success(path);
    }

    @GetResource(path = "/ncGroupMembers/{groupId}", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "查询 Nextcloud 组成员列表")
    public ResponseData<List<String>> getNextcloudGroupMembers(@PathVariable String groupId) {
        return ResponseData.success(nextcloudService.getGroupMembers(groupId));
    }

    @GetResource(path = "/getSpaceByAppSpaceId", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "通过第三方应用空间站ID查询空间站信息")
    public ResponseData<SpaceEntity> getSpaceByAppSpaceId(String appSpaceId) {
        SpaceAppRelEntity rel = spaceAppRelService.getByAppSpaceId(appSpaceId);
        if (rel == null) {
            return ResponseData.success(null);
        }
        SpaceEntity space = spaceService.getBySpaceId(rel.getSpaceId());
        return ResponseData.success(space);
    }

}

