     * @param response HTTP响应对象
     * @return 登录结果
     */
    @PostResource(path = "/odLogin", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "od login", description = "od use password and username login")
    public ResponseData<Void> odLogin(@Valid @RequestBody OdLoginRo loginRo,
                                      HttpServletResponse response) throws IOException {
        // 调用业务层进行登录验证
        boolean loginSuccess = authService.validateAndLogin(loginRo);

        if (loginSuccess) {
            // 登录成功，执行重定向, 此处不需要重定向，改成前端请求
            // response.sendRedirect(loginRo.getRedirectUrl());
            return ResponseData.success();
        } else {
            // 登录失败
            return ResponseData.error("用户名或密码错误");
        }
    }

    @GetResource(path = "/oidc/logout", requiredPermission = false, requiredLogin = false)
    public void oidcLogout(
            @RequestParam(name = "post_logout_redirect_uri", required = false) String postLogoutRedirectUri,
            @RequestParam(name = "client_id", required = false) String clientId,
            HttpServletRequest request,
            HttpServletResponse response) throws IOException {
        SessionContext.cleanContext(request);
        SessionContext.removeCookie(response, cookieProperties.getI18nCookieName(), "/");
        SessionContext.removeCookie(response, cookieProperties.getI18nCookieName(), "/", cookieProperties.getDomainName());
        if (StringUtils.isNotBlank(cookieProperties.getCookieName())) {
            SessionContext.removeCookie(response, cookieProperties.getCookieName(), "/");
            SessionContext.removeCookie(response, cookieProperties.getCookieName(), "/", cookieProperties.getDomainName());
        }
        JwtUtil.clearJwtCookie(response);
        if (StringUtils.isNotBlank(postLogoutRedirectUri)) {
            response.sendRedirect(postLogoutRedirectUri);
        } else {
            response.sendRedirect("/");
        }
    }
}

