    // 维度 4: 参数校验
    await testParamValidation();

    // 维度 5: 注入防护
    await testInjectionAndSpecialChars();

    // 维度 6: 写操作验证
    await testWriteAndVerify();

    // 维度 7: MM Webhook 鉴权
