// ────── 维度 6: 写操作验证（状态更新） ──────
async function testWriteAndVerify() {
  console.log('\n⚡ 6. 写操作验证 — 状态更新幂等性');

  const listRes = await GET('/feedback/list?pageNum=1&pageSize=1');
  if (!listRes.data?.records?.length) {
    console.log('  ⚠️ 无数据，跳过');
    return;
  }
  const target = listRes.data.records[0];
  const originalStatus = target.status;
  const newStatus = originalStatus === 0 ? 1 : 0;

  // 修改状态
  const r1 = await POST('/feedback/update-status', { feedbackId: target.id, status: newStatus });
  assert('状态更新成功', r1.success === true, r1);

  // 查询验证
  const after = await GET('/feedback/list?pageNum=1&pageSize=100');
  const updated = after.data?.records?.find(r => r.id === target.id);
  assert('状态变更已生效', updated?.status === newStatus, updated?.status);

  // 幂等：相同操作再执行一次
  const r2 = await POST('/feedback/update-status', { feedbackId: target.id, status: newStatus });
  assert('相同状态更新不报错', r2.success === true, r2);

  // 还原
  await POST('/feedback/update-status', { feedbackId: target.id, status: originalStatus });
  console.log(`  ℹ️  已还原为 status=${originalStatus}`);
}

