  console.log('  10. 响应结构一致性');
  console.log('  11. 多来源数据对比（站内 vs MM）');
  console.log('  12. 数据排序验证');
  console.log('  13. 未登录访问 + 错误码规范性');

  console.log('\n👤 测试账号:');
