// ────── 维度 2: 分页边界 ──────
async function testPaginationBoundary() {
  console.log('\n📐 2. 分页边界');

  // pageSize=1
  const p1 = await GET('/feedback/list?pageNum=1&pageSize=1');
  assert('pageSize=1 返回成功', p1.success === true, p1);
  assert('pageSize=1 最多返回1条', p1.data?.records?.length <= 1, p1.data?.records?.length);

  // 大 pageSize
  const p100 = await GET('/feedback/list?pageNum=1&pageSize=100');
  assert('pageSize=100 返回成功', p100.success === true);

  // total 一致性
  if (p100.data?.total != null && p1.data?.total != null) {
    assert('不同 pageSize 下 total 一致', p1.data.total === p100.data.total);
  }

  // total 与 records 一致性
  if (p100.data?.total <= 100) {
    assert('total <= 100 时 length === total',
      p100.data.records.length === p100.data.total,
      `records.length=${p100.data.records.length}, total=${p100.data.total}`);
  }

  // 超出最后一页
  const overPage = await GET('/feedback/list?pageNum=9999&pageSize=20');
  assert('超页返回空列表', overPage.data?.records?.length === 0, overPage.data?.records?.length);
  assert('超页 total 不变', overPage.data?.total === p100.data?.total);

  // 两页不重复
  if (p1.data?.total > 1) {
    const p2 = await GET('/feedback/list?pageNum=2&pageSize=1');
    assert('第2页有数据', p2.data?.records?.length > 0);
    if (p1.data?.records?.[0] && p2.data?.records?.[0]) {
      assert('两页 ID 不重复',
        p1.data.records[0].id !== p2.data.records[0].id);
    }
  }

  // 不传分页参数用默认值
  const noPage = await GET('/feedback/list');
  assert('不传分页参数返回成功', noPage.success === true);
  assert('默认 records 不超过 20', noPage.data?.records?.length <= 20, noPage.data?.records?.length);
}

// ────── 维度 3: 筛选与搜索 ──────
async function testFilterAndSearch() {
  console.log('\n🔎 3. 筛选与搜索');

  // 按状态筛选
  const status0 = await GET('/feedback/list?status=0&pageNum=1&pageSize=20');
  assert('status=0 筛选返回成功', status0.success === true, status0);
  if (status0.data?.records?.length > 0) {
    const allStatus0 = status0.data.records.every(r => r.status === 0);
    assert('status=0 筛选结果全部为未处理', allStatus0);
  }

  const status1 = await GET('/feedback/list?status=1&pageNum=1&pageSize=20');
  assert('status=1 筛选返回成功', status1.success === true);
  if (status1.data?.records?.length > 0) {
    const allStatus1 = status1.data.records.every(r => r.status === 1);
    assert('status=1 筛选结果全部为已处理', allStatus1);
  }

  // 按 feedbackType 筛选
  const bugList = await GET(`/feedback/list?feedbackType=bug&pageNum=1&pageSize=20`);
  assert('feedbackType=bug 筛选返回成功', bugList.success === true);
  if (bugList.data?.records?.length > 0) {
    const allBug = bugList.data.records.every(r => r.feedbackType === 'bug');
    assert('feedbackType=bug 筛选结果全部为bug', allBug);
  }

  // 按 source 筛选（虽然接口没有 source 筛选参数，但 keyword 搜索覆盖 content）

  // keyword 搜索
  const all = await GET('/feedback/list?pageNum=1&pageSize=100');
  if (all.data?.records?.length > 0) {
    const realContent = all.data.records[0].content;
    if (realContent && realContent.length > 2) {
      const partial = realContent.substring(0, 2);
      const partialRes = await GET(`/feedback/list?keyword=${encodeURIComponent(partial)}&pageNum=1&pageSize=20`);
      assert(`部分匹配"${partial}"有结果`, partialRes.data?.records?.length > 0, partialRes.data?.records?.length);
    }
  }

  // 空 keyword 等同不传
  const noKw = await GET('/feedback/list?pageNum=1&pageSize=20');
  const emptyKw = await GET('/feedback/list?keyword=&pageNum=1&pageSize=20');
  assert('空 keyword 等同不传', emptyKw.data?.total === noKw.data?.total);

  // 纯空格
  const spaceKw = await GET(`/feedback/list?keyword=${encodeURIComponent('   ')}&pageNum=1&pageSize=20`);
  assert('纯空格 keyword 不报500', spaceKw.success === true || (spaceKw.code && spaceKw.code !== 500), spaceKw);

  // 不存在的关键词
  const none = await GET(`/feedback/list?keyword=${encodeURIComponent('ZZZZZZZZZ不可能存在的关键词')}&pageNum=1&pageSize=20`);
  assert('不存在关键词返回空', none.data?.records?.length === 0, none.data?.records?.length);

  // 日期范围筛选
  const today = new Date().toISOString().split('T')[0]; // yyyy-MM-dd
  const dateRes = await GET(`/feedback/list?startDate=${today}&endDate=${today}&pageNum=1&pageSize=20`);
  assert('日期范围筛选返回成功', dateRes.success === true, dateRes);

  // 多条件组合
  const combo = await GET(`/feedback/list?status=0&feedbackType=bug&pageNum=1&pageSize=20`);
  assert('多条件组合筛选返回成功', combo.success === true, combo);
  if (combo.data?.records?.length > 0) {
    const allMatch = combo.data.records.every(r => r.status === 0 && r.feedbackType === 'bug');
    assert('多条件组合结果都满足', allMatch);
  }
}

