// ────── 维度 5: 特殊字符与注入防护 ──────
async function testInjectionAndSpecialChars() {
  console.log('\n🛡️ 5. 注入防护 + 特殊字符');

  // keyword 特殊字符
  const specialChars = ['%', '_', '\'', '"', '\\', '<script>alert(1)</script>', '&&', '||'];
  for (const ch of specialChars) {
    const res = await GET(`/feedback/list?keyword=${encodeURIComponent(ch)}&pageNum=1&pageSize=20`);
    assert(`keyword 特殊字符 "${ch}" 不报500`,
      res.success === true || (res.code && res.code !== 500), res);
  }

  // SQL 注入
  const injections = [
    "' OR 1=1 --",
    "1; DROP TABLE collabspace_feedback;",
    "' UNION SELECT * FROM collabspace_feedback --",
  ];
  for (const payload of injections) {
    const res = await GET(`/feedback/list?keyword=${encodeURIComponent(payload)}&pageNum=1&pageSize=20`);
    assert(`SQL注入 "${payload.slice(0, 30)}..." 不报500`,
      res.success === true || (res.code && res.code !== 500), res);
  }

  // 超长 keyword
  const longStr = 'a'.repeat(300);
  const longRes = await GET(`/feedback/list?keyword=${encodeURIComponent(longStr)}&pageNum=1&pageSize=20`);
  assert('超长 keyword 不报500',
    longRes.success === true || (longRes.code && longRes.code !== 500), longRes);

  // 超长 content 提交
  const formLong = new FormData();
  formLong.append('data', new Blob([JSON.stringify({
    feedbackType: 'other',
    content: '测试'.repeat(500),
  })], { type: 'application/json' }));
  const longSubmit = await POST('/feedback/submit', formLong);
  assert('超长 content 提交不报500',
    longSubmit.success === true || (longSubmit.code && longSubmit.code !== 500), longSubmit);
  // 如果成功了记录ID后续清理
  if (longSubmit.success === true) {
    const check = await GET(`/feedback/list?keyword=${encodeURIComponent('测试测试测试')}&pageNum=1&pageSize=1`);
    if (check.data?.records?.[0]) createdFeedbackIds.push(check.data.records[0].id);
  }

  // XSS payload 提交
  const formXss = new FormData();
  formXss.append('data', new Blob([JSON.stringify({
    feedbackType: 'bug',
    content: '<script>alert("xss")</script><img onerror="alert(1)" src="x">',
    relatedLink: 'javascript:alert(1)',
  })], { type: 'application/json' }));
  const xssRes = await POST('/feedback/submit', formXss);
  assert('XSS payload 提交不报500',
    xssRes.success === true || (xssRes.code && xssRes.code !== 500), xssRes);
}

// ────── 维度 6: 写操作验证（状态更新） ──────
async function testWriteAndVerify() {
  console.log('\n⚡ 6. 写操作验证 — 状态更新幂等性');

  const listRes = await GET('/feedback/list?pageNum=1&pageSize=1');
  if (!listRes.data?.records?.length) {
    console.log('  ⚠️ 无数据，跳过');
    return;
  }
  const target = listRes.data.records[0];
  const originalStatus = target.status;
  const newStatus = originalStatus === 0 ? 1 : 0;

  // 修改状态
  const r1 = await POST('/feedback/update-status', { feedbackId: target.id, status: newStatus });
  assert('状态更新成功', r1.success === true, r1);

  // 查询验证
  const after = await GET('/feedback/list?pageNum=1&pageSize=100');
  const updated = after.data?.records?.find(r => r.id === target.id);
  assert('状态变更已生效', updated?.status === newStatus, updated?.status);

  // 幂等：相同操作再执行一次
  const r2 = await POST('/feedback/update-status', { feedbackId: target.id, status: newStatus });
  assert('相同状态更新不报错', r2.success === true, r2);

  // 还原
  await POST('/feedback/update-status', { feedbackId: target.id, status: originalStatus });
  console.log(`  ℹ️  已还原为 status=${originalStatus}`);
}

