  const noUserRes = await POST('/feedback/mm-webhook', {
    content: '缺少userName',
  }, { 'X-Webhook-Token': CONFIG.mmWebhookToken });
  assert('mm-webhook 缺少 userName 返回错误', noUserRes.success === false, noUserRes);

  // mm-webhook userName 为空字符串
  const emptyUserRes = await POST('/feedback/mm-webhook', {
    userName: '',
    content: 'userName为空',
  }, { 'X-Webhook-Token': CONFIG.mmWebhookToken });
  assert('mm-webhook userName 为空返回错误', emptyUserRes.success === false, emptyUserRes);
}

// ────── 维度 5: 特殊字符与注入防护 ──────
async function testInjectionAndSpecialChars() {
  console.log('\n🛡️ 5. 注入防护 + 特殊字符');

  // keyword 特殊字符
  const specialChars = ['%', '_', '\'', '"', '\\', '<script>alert(1)</script>', '&&', '||'];
  for (const ch of specialChars) {
    const res = await GET(`/feedback/list?keyword=${encodeURIComponent(ch)}&pageNum=1&pageSize=20`);
    assert(`keyword 特殊字符 "${ch}" 不报500`,
      res.success === true || (res.code && res.code !== 500), res);
  }

  // SQL 注入
  const injections = [
    "' OR 1=1 --",
    "1; DROP TABLE collabspace_feedback;",
    "' UNION SELECT * FROM collabspace_feedback --",
  ];
  for (const payload of injections) {
    const res = await GET(`/feedback/list?keyword=${encodeURIComponent(payload)}&pageNum=1&pageSize=20`);
    assert(`SQL注入 "${payload.slice(0, 30)}..." 不报500`,
      res.success === true || (res.code && res.code !== 500), res);
  }

  // 超长 keyword
  const longStr = 'a'.repeat(300);
  const longRes = await GET(`/feedback/list?keyword=${encodeURIComponent(longStr)}&pageNum=1&pageSize=20`);
  assert('超长 keyword 不报500',
    longRes.success === true || (longRes.code && longRes.code !== 500), longRes);

  // 超长 content 提交
  const formLong = new FormData();
  formLong.append('data', new Blob([JSON.stringify({
    feedbackType: 'other',
    content: '测试'.repeat(500),
  })], { type: 'application/json' }));
  const longSubmit = await POST('/feedback/submit', formLong);
  assert('超长 content 提交不报500',
    longSubmit.success === true || (longSubmit.code && longSubmit.code !== 500), longSubmit);
  // 如果成功了记录ID后续清理
  if (longSubmit.success === true) {
    const check = await GET(`/feedback/list?keyword=${encodeURIComponent('测试测试测试')}&pageNum=1&pageSize=1`);
    if (check.data?.records?.[0]) createdFeedbackIds.push(check.data.records[0].id);
  }

  // XSS payload 提交
  const formXss = new FormData();
  formXss.append('data', new Blob([JSON.stringify({
    feedbackType: 'bug',
    content: '<script>alert("xss")</script><img onerror="alert(1)" src="x">',
    relatedLink: 'javascript:alert(1)',
  })], { type: 'application/json' }));
  const xssRes = await POST('/feedback/submit', formXss);
  assert('XSS payload 提交不报500',
    xssRes.success === true || (xssRes.code && xssRes.code !== 500), xssRes);
}

// ────── 维度 6: 写操作验证（状态更新） ──────
async function testWriteAndVerify() {
  console.log('\n⚡ 6. 写操作验证 — 状态更新幂等性');

  const listRes = await GET('/feedback/list?pageNum=1&pageSize=1');
  if (!listRes.data?.records?.length) {
    console.log('  ⚠️ 无数据，跳过');
    return;
  }
  const target = listRes.data.records[0];
  const originalStatus = target.status;
  const newStatus = originalStatus === 0 ? 1 : 0;

  // 修改状态
  const r1 = await POST('/feedback/update-status', { feedbackId: target.id, status: newStatus });
  assert('状态更新成功', r1.success === true, r1);

  // 查询验证
  const after = await GET('/feedback/list?pageNum=1&pageSize=100');
  const updated = after.data?.records?.find(r => r.id === target.id);
  assert('状态变更已生效', updated?.status === newStatus, updated?.status);

  // 幂等：相同操作再执行一次
  const r2 = await POST('/feedback/update-status', { feedbackId: target.id, status: newStatus });
  assert('相同状态更新不报错', r2.success === true, r2);

  // 还原
  await POST('/feedback/update-status', { feedbackId: target.id, status: originalStatus });
  console.log(`  ℹ️  已还原为 status=${originalStatus}`);
}

// ────── 维度 7: MM Webhook 鉴权 ──────
async function testMmWebhookAuth() {
  console.log('\n🔐 7. MM Webhook 鉴权');

  // 无 token
  const noTokenRes = await POST_RAW('/feedback/mm-webhook', {
    userName: '测试',
    content: '无token',
  });
  const noTokenBody = await noTokenRes.json().catch(() => null);
  assert('无 X-Webhook-Token 返回非200或业务错误',
    noTokenRes.status !== 200 || noTokenBody?.success === false,
    `status=${noTokenRes.status}, body=${JSON.stringify(noTokenBody).slice(0, 200)}`);

  // 错误 token
  const wrongTokenRes = await POST('/feedback/mm-webhook', {
    userName: '测试',
    content: '错误token',
  }, { 'X-Webhook-Token': 'wrong_token_12345' });
  assert('错误 token 返回 success=false', wrongTokenRes.success === false, wrongTokenRes);

  // 空 token
  const emptyTokenRes = await POST('/feedback/mm-webhook', {
    userName: '测试',
    content: '空token',
  }, { 'X-Webhook-Token': '' });
  assert('空 token 返回 success=false', emptyTokenRes.success === false, emptyTokenRes);
}

// ────── 维度 8: 不存在/异常数据 ──────
async function testNotExistData() {
  console.log('\n🚫 8. 不存在的数据');

  // 更新不存在的反馈ID（用合法 Long 值，避免超范围500）
  const res = await POST('/feedback/update-status', { feedbackId: 1, status: 1 });
  assert('不存在 feedbackId 不报500', res.code !== 500, res);

  // 无效状态值
  const invalidStatus = await POST('/feedback/update-status', { feedbackId: 1, status: 99 });
  assert('无效 status 值不报500',
    invalidStatus.code !== 500 || invalidStatus.success !== undefined,
    invalidStatus);

  // 无效日期格式
  const badDate = await GET(`/feedback/list?startDate=not-a-date&pageNum=1&pageSize=20`);
  assert('无效日期格式不报500',
    badDate.success === true || (badDate.code && badDate.code !== 500),
    badDate);

  // feedbackId 为字符串（JSON 反序列化时会报错）
  const strIdRes = await POST('/feedback/update-status', { feedbackId: 'abc', status: 1 });
  assert('feedbackId 为字符串不报500',
    strIdRes.code !== 500 || strIdRes.success === false,
    strIdRes);
}

// ────── 维度 9: 并发请求 ──────
async function testConcurrency() {
  console.log('\n🔀 9. 并发请求');

  // 5个并发 GET
  const promises = Array.from({ length: 5 }, (_, i) =>
    GET(`/feedback/list?pageNum=${i + 1}&pageSize=5`)
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('5个并发 GET 请求都成功', allOk, results.map(r => r.success));

  // 并发提交反馈
  const submitPromises = Array.from({ length: 3 }, (_, i) => {
    const fd = new FormData();
    fd.append('data', new Blob([JSON.stringify({
      feedbackType: 'other',
      content: `【自动化测试】并发提交 #${i}`,
    })], { type: 'application/json' }));
    return POST('/feedback/submit', fd);
  });
  const submitResults = await Promise.all(submitPromises);
  const allSubmitOk = submitResults.every(r => r.success === true);
  assert('3个并发 submit 都成功', allSubmitOk, submitResults.map(r => r.success));

  // 记录并发提交的ID用于清理
  const checkList = await GET(`/feedback/list?keyword=${encodeURIComponent('【自动化测试】并发提交')}&pageNum=1&pageSize=10`);
  if (checkList.data?.records) {
    for (const r of checkList.data.records) {
      createdFeedbackIds.push(r.id);
    }
  }
}

// ────── 维度 10: 响应结构一致性 ──────
async function testResponseStructure() {
  console.log('\n📦 10. 响应结构一致性');

  const res = await GET('/feedback/list?pageNum=1&pageSize=5');
  assert('含 current', typeof res.data?.current === 'number', res.data?.current);
  assert('含 size', typeof res.data?.size === 'number', res.data?.size);
  assert('size 与请求一致', res.data?.size === 5, res.data?.size);
  assert('含 total', typeof res.data?.total === 'number', res.data?.total);
  assert('含 records', Array.isArray(res.data?.records), res.data?.records);
  assert('records.length <= size', res.data?.records?.length <= 5, res.data?.records?.length);

  // pages 字段
  if (res.data?.total != null && res.data?.size != null) {
    const expectedPages = Math.ceil(res.data.total / res.data.size) || 1;
    assert('pages 字段正确', res.data.pages === expectedPages || res.data.pages === 0,
      `pages=${res.data.pages}, expected=${expectedPages}`);
  }

  // 成功响应结构
  const submitFd = new FormData();
  submitFd.append('data', new Blob([JSON.stringify({
    feedbackType: 'feat',
    content: '【自动化测试】响应结构检查',
  })], { type: 'application/json' }));
  const submitRes = await POST('/feedback/submit', submitFd);
  assert('submit 返回含 success 字段', typeof submitRes.success === 'boolean', submitRes);
  assert('submit 返回含 code 字段', typeof submitRes.code === 'number', submitRes);

  // 记录清理
  const check = await GET(`/feedback/list?keyword=${encodeURIComponent('【自动化测试】响应结构检查')}&pageNum=1&pageSize=1`);
  if (check.data?.records?.[0]) createdFeedbackIds.push(check.data.records[0].id);
}

// ────── 维度 11: 多来源数据对比 ──────
async function testMultiSourceData() {
  console.log('\n📦 11. 多来源数据对比（站内 vs MM）');

  // 提交一条站内反馈
  const fd = new FormData();
  fd.append('data', new Blob([JSON.stringify({
    feedbackType: 'lag',
    content: '【自动化测试】来源对比-站内',
  })], { type: 'application/json' }));
  await POST('/feedback/submit', fd);

  // 提交一条 MM 反馈
  await POST('/feedback/mm-webhook', {
    userName: '来源对比测试',
    content: '【自动化测试】来源对比-MM',
  }, { 'X-Webhook-Token': CONFIG.mmWebhookToken });

  // 查询并对比
  const list = await GET(`/feedback/list?keyword=${encodeURIComponent('【自动化测试】来源对比')}&pageNum=1&pageSize=20`);
  const sentryItems = list.data?.records?.filter(r => r.source === 'sentry') || [];
  const mmItems = list.data?.records?.filter(r => r.source === 'mm') || [];
  assert('站内反馈 source=sentry', sentryItems.length > 0, sentryItems.length);
  assert('MM反馈 source=mm', mmItems.length > 0, mmItems.length);

  // 验证两种来源的字段结构一致
  if (sentryItems.length > 0 && mmItems.length > 0) {
    const sentryKeys = Object.keys(sentryItems[0]).sort();
    const mmKeys = Object.keys(mmItems[0]).sort();
    assert('两种来源字段结构一致', sentryKeys.join(',') === mmKeys.join(','),
      `sentry: ${sentryKeys.join(',')}\nmm: ${mmKeys.join(',')}`);
  }

  // 记录清理
  for (const r of (list.data?.records || [])) {
    createdFeedbackIds.push(r.id);
  }
}

// ────── 维度 12: 数据排序验证 ──────
async function testSorting() {
  console.log('\n📊 12. 数据排序验证');

  const list = await GET('/feedback/list?pageNum=1&pageSize=50');
  if (list.data?.records?.length >= 2) {
    // 验证按 feedbackTime 降序
    let isDescending = true;
    for (let i = 1; i < list.data.records.length; i++) {
      const prev = new Date(list.data.records[i - 1].feedbackTime);
      const curr = new Date(list.data.records[i].feedbackTime);
      if (prev < curr) {
        isDescending = false;
        break;
      }
    }
    assert('列表按 feedbackTime 降序排列', isDescending);
  } else {
    console.log('  ⚠️ 数据不足2条，跳过排序验证');
  }
}

// ────── 维度 13: 未登录访问 ──────
async function testUnloggedAccess() {
  console.log('\n🔒 13. 未登录访问 + 错误码规范性');

  saveSession('main');
  cookie = ''; // 清除登录状态

  // 未登录访问 list（需要登录的接口）
  const listRes = await rawFetch('GET', `${CONFIG.host}/api/v1/feedback/list?pageNum=1&pageSize=20`);
  assert('未登录 GET /list 不报500', listRes.status !== 500, listRes.status);

  // 未登录提交反馈
  const fd = new FormData();
  fd.append('data', new Blob([JSON.stringify({
    feedbackType: 'bug',
    content: '未登录提交',
  })], { type: 'application/json' }));
  const submitRes = await rawFetch('POST', `${CONFIG.host}/api/v1/feedback/submit`, fd);
  assert('未登录 POST /submit 返回非200', submitRes.status !== 200 || (await submitRes.clone().json().catch(() => ({}))).success === false,
    submitRes.status);

  // 未登录更新状态
  const updateRes = await rawFetch('POST', `${CONFIG.host}/api/v1/feedback/update-status`,
    { feedbackId: 1, status: 1 });
  assert('未登录 POST /update-status 返回非200', updateRes.status !== 200 || (await updateRes.clone().json().catch(() => ({}))).success === false,
    updateRes.status);

  // MM webhook 不需要登录，但需要 token
  const mmNoLogin = await POST_RAW('/feedback/mm-webhook', {
    userName: '未登录测试',
    content: '不需要登录',
  }, { 'X-Webhook-Token': CONFIG.mmWebhookToken });
  const mmBody = await mmNoLogin.json().catch(() => null);
  assert('MM webhook 无需登录即可调用', mmBody?.success === true, mmBody);

  // 如果成功了记录清理
  if (mmBody?.success === true) {
    restoreSession('main');
    const check = await GET(`/feedback/list?keyword=${encodeURIComponent('不需要登录')}&pageNum=1&pageSize=1`);
    if (check.data?.records?.[0]) createdFeedbackIds.push(check.data.records[0].id);
  }

  restoreSession('main');
}

// ────── 清理测试数据 ──────
async function cleanup() {
  console.log('\n🧹 清理测试数据');

  // 通过搜索关键词找所有测试数据
  const testData = await GET(`/feedback/list?keyword=${encodeURIComponent('【自动化测试】')}&pageNum=1&pageSize=100`);
  if (testData.data?.records?.length > 0) {
    console.log(`  ℹ️  发现 ${testData.data.records.length} 条测试数据`);
    // 由于没有删除接口，只能标记状态（或通过数据库清理）
    console.log('  ℹ️  当前无删除接口，测试数据保留在库中（is_deleted=0），需手动清理');
    console.log(`  ℹ️  清理SQL: DELETE FROM collabspace_feedback WHERE content LIKE '%【自动化测试】%';`);
  } else {
    console.log('  ℹ️  无测试数据需要清理');
  }
}

// ========== 执行 ==========
async function main() {
  console.log('🚀 2087-消息推送与反馈收集 — Feedback 接口测试');
  console.log(`   环境: ${CONFIG.host}`);
  console.log(`   时间: ${new Date().toISOString()}\n`);

  try {
    await login();

    // 维度 1: 正常流程
    await testBasicSubmitAndList();

    // 维度 1b: MM Webhook
    await testMmWebhook();

    // 维度 2: 分页边界
    await testPaginationBoundary();

    // 维度 3: 筛选与搜索
    await testFilterAndSearch();

    // 维度 4: 参数校验
    await testParamValidation();

    // 维度 5: 注入防护
    await testInjectionAndSpecialChars();

    // 维度 6: 写操作验证
    await testWriteAndVerify();

    // 维度 7: MM Webhook 鉴权
    await testMmWebhookAuth();

    // 维度 8: 不存在/异常数据
    await testNotExistData();

    // 维度 9: 并发请求
    await testConcurrency();

    // 维度 10: 响应结构一致性
    await testResponseStructure();

    // 维度 11: 多来源数据对比
    await testMultiSourceData();

    // 维度 12: 排序验证
    await testSorting();

    // 维度 13: 未登录访问 + 错误码
    await testUnloggedAccess();

    // 清理
    await cleanup();

  } catch (e) {
    if (e.cause?.code === 'ECONNREFUSED') {
      console.log('\n❌ 无法连接测试环境，请检查网络');
    } else {
      console.log(`\n❌ 异常: ${e.stack || e.message}`);
    }
    process.exit(1);
  }

  console.log(`\n=============================`);
  console.log(`✅ 通过: ${passed}  ❌ 失败: ${failed}  📊 总计: ${passed + failed}`);
  console.log(`=============================`);

  if (failed > 0) {
    console.log('\n⚠️  失败用例需要分析：是测试 bug 还是接口 bug');
  }

  console.log('\n📋 覆盖维度清单:');
  console.log('  1.  正常流程（站内提交+列表+状态更新）');
  console.log('  1b. MM Webhook 正常流程');
  console.log('  2.  分页边界');
  console.log('  3.  筛选与搜索（状态/类型/日期/关键词/组合）');
  console.log('  4.  参数校验（必填字段/空值）');
  console.log('  5.  注入防护 + 特殊字符（SQL注入/XSS/超长）');
  console.log('  6.  写操作验证（状态更新幂等性）');
  console.log('  7.  MM Webhook 鉴权（无token/错token/空token）');
  console.log('  8.  不存在/异常数据');
  console.log('  9.  并发请求');
  console.log('  10. 响应结构一致性');
  console.log('  11. 多来源数据对比（站内 vs MM）');
  console.log('  12. 数据排序验证');
  console.log('  13. 未登录访问 + 错误码规范性');

  console.log('\n👤 测试账号:');
  console.log(`  主账号: ${CONFIG.loginEmail}`);
  console.log(`  MM Webhook Token: ${CONFIG.mmWebhookToken.slice(0, 6)}...`);

  process.exit(failed > 0 ? 1 : 0);
}

main();

