// ────── 维度 1: 正常流程 ──────
async function testBasicSubmitAndList() {
  console.log('📋 1. 基本 CRUD —— 站内反馈提交 + 列表查询 + 状态更新');

  // 1.1 提交反馈（multipart/form-data）
  const formData = new FormData();
  const dataBlob = new Blob([JSON.stringify({
    feedbackType: 'bug',
    content: '【自动化测试】文档加载缓慢，测试反馈',
    relatedLink: 'https://xcollabspace-test.xtool-staging.yottastudios.com/test',
    docType: 'onlyoffice',
  })], { type: 'application/json' });
  formData.append('data', dataBlob);

  const submitRes = await POST('/feedback/submit', formData);
  assert('提交反馈返回 success', submitRes.success === true, submitRes);

  // 1.2 查询反馈列表
  const listRes = await GET('/feedback/list?pageNum=1&pageSize=20');
  assert('列表查询返回 success', listRes.success === true, listRes);
  assert('data 不为 null', listRes.data != null, listRes.data);
  assert('包含 records 数组', Array.isArray(listRes.data?.records), listRes.data?.records);
  assert('包含 total', typeof listRes.data?.total === 'number', listRes.data?.total);
  assert('包含 size', typeof listRes.data?.size === 'number', listRes.data?.size);
  assert('包含 current', typeof listRes.data?.current === 'number', listRes.data?.current);

  // 1.3 验证刚提交的反馈出现在列表中
  const myFeedback = listRes.data?.records?.find(r =>
    r.content === '【自动化测试】文档加载缓慢，测试反馈'
  );
  assert('提交的反馈出现在列表中', myFeedback != null, listRes.data?.records?.map(r => r.content));

  if (myFeedback) {
    createdFeedbackIds.push(myFeedback.id);

    // 验证字段类型
    assert('记录含 id', myFeedback.id != null, myFeedback.id);
    assert('记录含 userId (string)', typeof myFeedback.userId === 'string', myFeedback.userId);
    assert('记录含 feedbackTime (string)', typeof myFeedback.feedbackTime === 'string', myFeedback.feedbackTime);
    assert('记录含 feedbackType === "bug"', myFeedback.feedbackType === 'bug', myFeedback.feedbackType);
    assert('记录含 docType === "onlyoffice"', myFeedback.docType === 'onlyoffice', myFeedback.docType);
    assert('记录含 relatedLink', typeof myFeedback.relatedLink === 'string', myFeedback.relatedLink);
    assert('记录含 content', typeof myFeedback.content === 'string', myFeedback.content);
    assert('记录含 attachments (数组)', Array.isArray(myFeedback.attachments), myFeedback.attachments);
    assert('记录含 source === "sentry"', myFeedback.source === 'sentry', myFeedback.source);
    assert('记录含 status === 0 (未处理)', myFeedback.status === 0, myFeedback.status);

    // 1.4 更新反馈状态
    const updateRes = await POST('/feedback/update-status', {
      feedbackId: myFeedback.id,
      status: 1,
    });
    assert('更新状态返回 success', updateRes.success === true, updateRes);

    // 验证状态变更
    const listRes2 = await GET('/feedback/list?pageNum=1&pageSize=20');
    const updated = listRes2.data?.records?.find(r => r.id === myFeedback.id);
    assert('状态已更新为1(已处理)', updated?.status === 1, updated?.status);

    // 还原状态
    await POST('/feedback/update-status', { feedbackId: myFeedback.id, status: 0 });
  }
}

