@Override
public void mmWebhookFeedback(MmFeedbackWebhookRo ro) {
    log.info("[lbl][2087-消息推送][Feedback][CREATE] MM消息同步写入, nickName={}, messageId={}, fileCount={}",
            ro.getFeedbackNickName(), ro.getMessageId(),
            ro.getFiles() != null ? ro.getFiles().size() : 0);

    // 从 files 列表提取 fileId，下载并上传到 MinIO
    List<String> fileIds = ro.getFiles() != null
            ? ro.getFiles().stream().map(MmFeedbackWebhookRo.MmFileInfo::getFileId).toList()
            : List.of();
    List<String> attachmentUrls = downloadMmFilesAndUpload(fileIds);

    // 解析 MM 传入的反馈时间
    LocalDateTime feedbackTime = LocalDateTime.now();
    if (StrUtil.isNotBlank(ro.getFeedbackTime())) {
        try {
            feedbackTime = LocalDateTime.parse(ro.getFeedbackTime(),
                    DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"));
        } catch (Exception e) {
            log.warn("[lbl][2087-消息推送][Feedback][CREATE] MM feedbackTime 解析失败, 使用当前时间, raw={}", ro.getFeedbackTime());
        }
    }

    // 将 messageId 存入 extraInfo
    String extraInfo = StrUtil.isNotBlank(ro.getMessageId())
            ? JSONUtil.toJsonStr(cn.hutool.core.map.MapUtil.of("messageId", ro.getMessageId()))
            : null;

    FeedbackEntity entity = FeedbackEntity.builder()
            .userId(ro.getFeedbackNickName())
            .userName(ro.getFeedbackNickName())
            .feedbackTime(feedbackTime)
            .content(ro.getContent())
            .attachments(attachmentUrls.isEmpty() ? null : JSONUtil.toJsonStr(attachmentUrls))
            .extraInfo(extraInfo)
            .source(FeedbackSource.MM.getCode())
            .status(FeedbackStatus.UNPROCESSED.getCode())
            .build();

    feedbackMapper.insert(entity);
    log.info("[lbl][2087-消息推送][Feedback][CREATE] MM消息同步写入成功, id={}, nickName={}, messageId={}",
            entity.getId(), ro.getFeedbackNickName(), ro.getMessageId());
}

