    // 将 messageId 存入 extraInfo
    String extraInfo = StrUtil.isNotBlank(ro.getMessageId())
            ? JSONUtil.toJsonStr(cn.hutool.core.map.MapUtil.of("messageId", ro.getMessageId()))
