/**
 * 2087-消息推送与反馈收集 — Feedback 接口测试脚本
 *
 * 用法: node test-feedback-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 自动登录测试环境，无需手动填 Cookie
 *
 * 接口覆盖:
 *   POST /feedback/submit         — 提交反馈（multipart/form-data，需登录）
 *   POST /feedback/mm-webhook     — MM机器人反馈写入（JSON，X-Webhook-Token鉴权）
 *   GET  /feedback/list           — 反馈列表查询（需登录）
 *   POST /feedback/update-status  — 更新反馈状态（需登录）
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'https://xcollabspace-test.xtool-staging.yottastudios.com',
  loginEmail: 'test@test.com',           // 主测试账号
  secondEmail: 'test2@test.com',         // 第二账号（多账号测试）
  mmWebhookToken: 'e9cqdhkexigkdpcesby4hksy5r', // MM webhook token (application.yml default)
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== TLS: 跳过自签名证书校验 ==========
process.env.NODE_TLS_REJECT_UNAUTHORIZED = '0';

// ========== HTTP 工具 ==========

function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const eqIdx = kv.indexOf('=');
    if (eqIdx > 0) {
      cookies[kv.substring(0, eqIdx).trim()] = kv.substring(eqIdx + 1).trim();
    }
  }
  return cookies;
}

function mergeCookies(existingCookie, newCookies) {
  const map = {};
  if (existingCookie) {
    for (const part of existingCookie.split(';')) {
      const eqIdx = part.indexOf('=');
      if (eqIdx > 0) map[part.substring(0, eqIdx).trim()] = part.substring(eqIdx + 1).trim();
    }
  }
  Object.assign(map, newCookies);
  return Object.entries(map).map(([k, v]) => `${k}=${v}`).join('; ');
}

async function rawFetch(method, url, body, extraHeaders = {}) {
  const headers = {
    ...extraHeaders,
  };
  if (cookie) headers['cookie'] = cookie;
  if (body && !(body instanceof FormData)) {
    headers['content-type'] = 'application/json';
  }

  const opts = { method, headers, redirect: 'manual' };
  if (body) {
    opts.body = body instanceof FormData ? body : JSON.stringify(body);
  }
  return fetch(url, opts);
}

/**
 * 安全解析 JSON：将大整数 ID 转为字符串，防止 JS 精度丢失
 * MyBatis-Plus 雪花 ID 是 19 位数字，超过 Number.MAX_SAFE_INTEGER
 */
function safeJsonParse(text) {
  // 将 JSON 中所有超过15位的纯数字值转为字符串（保留 key）
  const fixed = text.replace(/:\s*(\d{16,})\b/g, ':"$1"');
  return JSON.parse(fixed);
}

/**
 * 发送 POST 时，如果 body 包含大整数字符串的 feedbackId，需要发送原始数字
 * 用自定义 stringify 把字符串形式的大数字还原为裸数字
 */
function smartStringify(obj) {
  return JSON.stringify(obj).replace(/"feedbackId":"(\d+)"/g, '"feedbackId":$1');
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  const text = await res.text();
  return safeJsonParse(text);
}

async function POST(path, body, extraHeaders = {}) {
  let actualBody = body;
  if (body && !(body instanceof FormData) && typeof body === 'object') {
    // 使用 smartStringify 确保大整数 feedbackId 作为裸数字发送
    actualBody = smartStringify(body);
  }
  const headers = { ...extraHeaders };
  if (cookie) headers['cookie'] = cookie;
  if (actualBody && typeof actualBody === 'string') {
    headers['content-type'] = 'application/json';
  }
  const opts = { method: 'POST', headers, redirect: 'manual' };
  if (actualBody instanceof FormData) {
    opts.body = actualBody;
  } else if (typeof actualBody === 'string') {
    opts.body = actualBody;
  }
  const res = await fetch(`${CONFIG.host}/api/v1${path}`, opts);
  const text = await res.text();
  return safeJsonParse(text);
}

async function POST_RAW(path, body, extraHeaders = {}) {
  return rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body, extraHeaders);
}

// ========== 登录管理 ==========

async function login(email) {
  email = email || CONFIG.loginEmail;
  console.log(`🔑 登录 ${email} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  // testLogin sets JWT via cookie
  if (!cookies.JWT && !cookies.TJWT && !cookies.SESSION) {
    // 尝试 follow redirect
    const res2 = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`);
    const cookies2 = parseCookies(res2);
    if (!cookies2.JWT && !cookies2.TJWT && !cookies2.SESSION) {
      console.log('  ⚠️  登录可能失败（无 cookie 返回），尝试继续...');
      console.log('     set-cookie:', res.headers.getSetCookie?.());
    }
    cookie = mergeCookies('', cookies2);
  } else {
    cookie = mergeCookies('', cookies);
  }
  console.log(`  ✅ 登录完成\n`);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = cookie;
}
function restoreSession(name) {
  cookie = savedSessions[name];
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`,
    { redirect: 'manual' });
