// ────── 维度 5: 特殊字符与注入防护 ──────
async function testInjectionAndSpecialChars() {
  console.log('\n🛡️ 5. 注入防护 + 特殊字符');

  // keyword 特殊字符
  const specialChars = ['%', '_', '\'', '"', '\\', '<script>alert(1)</script>', '&&', '||'];
  for (const ch of specialChars) {
