/**
 * 2087-消息推送与反馈收集 — Feedback 接口测试脚本
 *
 * 用法: node test-feedback-api.js
 * 要求: Node.js 18+（原生 fetch）
 * 自动登录测试环境，无需手动填 Cookie
 *
 * 接口覆盖:
 *   POST /feedback/submit         — 提交反馈（multipart/form-data，需登录）
 *   POST /feedback/mm-webhook     — MM机器人反馈写入（JSON，X-Webhook-Token鉴权）
 *   GET  /feedback/list           — 反馈列表查询（需登录）
 *   POST /feedback/update-status  — 更新反馈状态（需登录）
 */

// ========== 配置 ==========
const CONFIG = {
  host: 'https://xcollabspace-test.xtool-staging.yottastudios.com',
  loginEmail: 'test@test.com',           // 主测试账号
  secondEmail: 'test2@test.com',         // 第二账号（多账号测试）
  mmWebhookToken: 'e9cqdhkexigkdpcesby4hksy5r', // MM webhook token (application.yml default)
};

// ========== 测试框架 ==========
let passed = 0;
let failed = 0;
let cookie = '';

function assert(name, condition, detail) {
  if (condition) {
    console.log(`  ✅ ${name}`);
    passed++;
  } else {
    console.log(`  ❌ ${name}`);
    if (detail !== undefined)
      console.log(`     实际值:`, typeof detail === 'object'
        ? JSON.stringify(detail).slice(0, 300) : detail);
    failed++;
  }
}

// ========== TLS: 跳过自签名证书校验 ==========
process.env.NODE_TLS_REJECT_UNAUTHORIZED = '0';

// ========== HTTP 工具 ==========

function parseCookies(res) {
  const cookies = {};
  const setCookieHeaders = res.headers.getSetCookie?.() || [];
  for (const header of setCookieHeaders) {
    const [kv] = header.split(';');
    const eqIdx = kv.indexOf('=');
    if (eqIdx > 0) {
      cookies[kv.substring(0, eqIdx).trim()] = kv.substring(eqIdx + 1).trim();
    }
  }
  return cookies;
}

function mergeCookies(existingCookie, newCookies) {
  const map = {};
  if (existingCookie) {
    for (const part of existingCookie.split(';')) {
      const eqIdx = part.indexOf('=');
      if (eqIdx > 0) map[part.substring(0, eqIdx).trim()] = part.substring(eqIdx + 1).trim();
    }
  }
  Object.assign(map, newCookies);
  return Object.entries(map).map(([k, v]) => `${k}=${v}`).join('; ');
}

async function rawFetch(method, url, body, extraHeaders = {}) {
  const headers = {
    ...extraHeaders,
  };
  if (cookie) headers['cookie'] = cookie;
  if (body && !(body instanceof FormData)) {
    headers['content-type'] = 'application/json';
  }

  const opts = { method, headers, redirect: 'manual' };
  if (body) {
    opts.body = body instanceof FormData ? body : JSON.stringify(body);
  }
  return fetch(url, opts);
}

/**
 * 安全解析 JSON：将大整数 ID 转为字符串，防止 JS 精度丢失
 * MyBatis-Plus 雪花 ID 是 19 位数字，超过 Number.MAX_SAFE_INTEGER
 */
function safeJsonParse(text) {
  // 将 JSON 中所有超过15位的纯数字值转为字符串（保留 key）
  const fixed = text.replace(/:\s*(\d{16,})\b/g, ':"$1"');
  return JSON.parse(fixed);
}

/**
 * 发送 POST 时，如果 body 包含大整数字符串的 feedbackId，需要发送原始数字
 * 用自定义 stringify 把字符串形式的大数字还原为裸数字
 */
function smartStringify(obj) {
  return JSON.stringify(obj).replace(/"feedbackId":"(\d+)"/g, '"feedbackId":$1');
}

async function GET(path) {
  const res = await rawFetch('GET', `${CONFIG.host}/api/v1${path}`);
  const text = await res.text();
  return safeJsonParse(text);
}

async function POST(path, body, extraHeaders = {}) {
  let actualBody = body;
  if (body && !(body instanceof FormData) && typeof body === 'object') {
    // 使用 smartStringify 确保大整数 feedbackId 作为裸数字发送
    actualBody = smartStringify(body);
  }
  const headers = { ...extraHeaders };
  if (cookie) headers['cookie'] = cookie;
  if (actualBody && typeof actualBody === 'string') {
    headers['content-type'] = 'application/json';
  }
  const opts = { method: 'POST', headers, redirect: 'manual' };
  if (actualBody instanceof FormData) {
    opts.body = actualBody;
  } else if (typeof actualBody === 'string') {
    opts.body = actualBody;
  }
  const res = await fetch(`${CONFIG.host}/api/v1${path}`, opts);
  const text = await res.text();
  return safeJsonParse(text);
}

async function POST_RAW(path, body, extraHeaders = {}) {
  return rawFetch('POST', `${CONFIG.host}/api/v1${path}`, body, extraHeaders);
}

// ========== 登录管理 ==========

async function login(email) {
  email = email || CONFIG.loginEmail;
  console.log(`🔑 登录 ${email} ...`);
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  // testLogin sets JWT via cookie
  if (!cookies.JWT && !cookies.TJWT && !cookies.SESSION) {
    // 尝试 follow redirect
    const res2 = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`);
    const cookies2 = parseCookies(res2);
    if (!cookies2.JWT && !cookies2.TJWT && !cookies2.SESSION) {
      console.log('  ⚠️  登录可能失败（无 cookie 返回），尝试继续...');
      console.log('     set-cookie:', res.headers.getSetCookie?.());
    }
    cookie = mergeCookies('', cookies2);
  } else {
    cookie = mergeCookies('', cookies);
  }
  console.log(`  ✅ 登录完成\n`);
}

let savedSessions = {};
function saveSession(name) {
  savedSessions[name] = cookie;
}
function restoreSession(name) {
  cookie = savedSessions[name];
}

async function loginAs(email) {
  const res = await fetch(`${CONFIG.host}/api/v1/testLogin/${encodeURIComponent(email)}`,
    { redirect: 'manual' });
  const cookies = parseCookies(res);
  if (!cookies.JWT && !cookies.TJWT && !cookies.SESSION) {
    console.log(`  ⚠️  登录 ${email} 可能失败，跳过`);
    return false;
  }
  cookie = mergeCookies('', cookies);
  return true;
}

// ========== 记录创建的反馈ID，用于清理 ==========
const createdFeedbackIds = [];

// ========== 测试用例 ==========

// ────── 维度 1: 正常流程 ──────
async function testBasicSubmitAndList() {
  console.log('📋 1. 基本 CRUD —— 站内反馈提交 + 列表查询 + 状态更新');

  // 1.1 提交反馈（multipart/form-data）
  const formData = new FormData();
  const dataBlob = new Blob([JSON.stringify({
    feedbackType: 'bug',
    content: '【自动化测试】文档加载缓慢，测试反馈',
    relatedLink: 'https://xcollabspace-test.xtool-staging.yottastudios.com/test',
    docType: 'onlyoffice',
  })], { type: 'application/json' });
  formData.append('data', dataBlob);

  const submitRes = await POST('/feedback/submit', formData);
  assert('提交反馈返回 success', submitRes.success === true, submitRes);

  // 1.2 查询反馈列表
  const listRes = await GET('/feedback/list?pageNum=1&pageSize=20');
  assert('列表查询返回 success', listRes.success === true, listRes);
  assert('data 不为 null', listRes.data != null, listRes.data);
  assert('包含 records 数组', Array.isArray(listRes.data?.records), listRes.data?.records);
  assert('包含 total', typeof listRes.data?.total === 'number', listRes.data?.total);
  assert('包含 size', typeof listRes.data?.size === 'number', listRes.data?.size);
  assert('包含 current', typeof listRes.data?.current === 'number', listRes.data?.current);

  // 1.3 验证刚提交的反馈出现在列表中
  const myFeedback = listRes.data?.records?.find(r =>
    r.content === '【自动化测试】文档加载缓慢，测试反馈'
  );
  assert('提交的反馈出现在列表中', myFeedback != null, listRes.data?.records?.map(r => r.content));

  if (myFeedback) {
    createdFeedbackIds.push(myFeedback.id);

    // 验证字段类型
    assert('记录含 id', myFeedback.id != null, myFeedback.id);
    assert('记录含 userId (string)', typeof myFeedback.userId === 'string', myFeedback.userId);
    assert('记录含 feedbackTime (string)', typeof myFeedback.feedbackTime === 'string', myFeedback.feedbackTime);
    assert('记录含 feedbackType === "bug"', myFeedback.feedbackType === 'bug', myFeedback.feedbackType);
    assert('记录含 docType === "onlyoffice"', myFeedback.docType === 'onlyoffice', myFeedback.docType);
    assert('记录含 relatedLink', typeof myFeedback.relatedLink === 'string', myFeedback.relatedLink);
    assert('记录含 content', typeof myFeedback.content === 'string', myFeedback.content);
    assert('记录含 attachments (数组)', Array.isArray(myFeedback.attachments), myFeedback.attachments);
    assert('记录含 source === "sentry"', myFeedback.source === 'sentry', myFeedback.source);
    assert('记录含 status === 0 (未处理)', myFeedback.status === 0, myFeedback.status);

    // 1.4 更新反馈状态
    const updateRes = await POST('/feedback/update-status', {
      feedbackId: myFeedback.id,
      status: 1,
    });
    assert('更新状态返回 success', updateRes.success === true, updateRes);

    // 验证状态变更
    const listRes2 = await GET('/feedback/list?pageNum=1&pageSize=20');
    const updated = listRes2.data?.records?.find(r => r.id === myFeedback.id);
    assert('状态已更新为1(已处理)', updated?.status === 1, updated?.status);

    // 还原状态
    await POST('/feedback/update-status', { feedbackId: myFeedback.id, status: 0 });
  }
}

// ────── 维度 1b: MM syncMessage 正常流程 ──────
async function testMmWebhook() {
  console.log('\n📋 1b. MM syncMessage 消息同步');

  // 正常提交（匹配 MM 实际 payload 格式）
  const res = await POST('/feedback/syncMessage', {
    files: [],
    content: '【自动化测试】MM机器人反馈内容',
    feedbackNickName: '自动化测试用户',
    feedbackTime: new Date().toISOString().replace('T', ' ').substring(0, 19),
    feedbackSource: 0,
    messageId: 'test-msg-' + Date.now(),
  });
  assert('syncMessage 返回 success', res.success === true, res);

  // 查询验证
  const listRes = await GET('/feedback/list?pageNum=1&pageSize=20');
  const mmFeedback = listRes.data?.records?.find(r =>
