// ────── 维度 9: 并发请求 ──────
async function testConcurrency() {
  console.log('\n🔀 9. 并发请求');

  // 5个并发 GET
  const promises = Array.from({ length: 5 }, (_, i) =>
    GET(`/feedback/list?pageNum=${i + 1}&pageSize=5`)
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('5个并发 GET 请求都成功', allOk, results.map(r => r.success));

  // 并发提交反馈
  const submitPromises = Array.from({ length: 3 }, (_, i) => {
    const fd = new FormData();
    fd.append('data', new Blob([JSON.stringify({
      feedbackType: 'other',
      content: `【自动化测试】并发提交 #${i}`,
    })], { type: 'application/json' }));
    return POST('/feedback/submit', fd);
  });
  const submitResults = await Promise.all(submitPromises);
  const allSubmitOk = submitResults.every(r => r.success === true);
  assert('3个并发 submit 都成功', allSubmitOk, submitResults.map(r => r.success));

  // 记录并发提交的ID用于清理
  const checkList = await GET(`/feedback/list?keyword=${encodeURIComponent('【自动化测试】并发提交')}&pageNum=1&pageSize=10`);
  if (checkList.data?.records) {
    for (const r of checkList.data.records) {
      createdFeedbackIds.push(r.id);
    }
  }
}

