// ────── 维度 12: 数据排序验证 ──────
async function testSorting() {
  console.log('\n📊 12. 数据排序验证');

  const list = await GET('/feedback/list?pageNum=1&pageSize=50');
  if (list.data?.records?.length >= 2) {
    // 验证按 feedbackTime 降序
    let isDescending = true;
    for (let i = 1; i < list.data.records.length; i++) {
      const prev = new Date(list.data.records[i - 1].feedbackTime);
      const curr = new Date(list.data.records[i].feedbackTime);
      if (prev < curr) {
        isDescending = false;
        break;
      }
    }
    assert('列表按 feedbackTime 降序排列', isDescending);
  } else {
    console.log('  ⚠️ 数据不足2条，跳过排序验证');
  }
}

