  assert('[BUG] 不存在 feedbackId 应返回业务错误而非500（当前抛 RuntimeException）',
    res.message === '反馈记录不存在' || res.success === false, res);

  // 无效状态值
  const invalidStatus = await POST('/feedback/update-status', { feedbackId: 1, status: 99 });
  assert('无效 status 值不报500',
    invalidStatus.code !== 500 || invalidStatus.success !== undefined,
    invalidStatus);

  // 无效日期格式
  // 注：当前 LocalDate.parse 抛 DateTimeParseException → 全局异常处理器返回 HTTP 500
  // 这是一个接口 bug：应在 Service 层 catch 并返回参数校验错误
  const badDate = await GET(`/feedback/list?startDate=not-a-date&pageNum=1&pageSize=20`);
  assert('[BUG] 无效日期格式应返回参数错误（当前抛 DateTimeParseException → 500）',
    badDate.success === false, badDate);

  // feedbackId 为字符串（JSON 反序列化时会报错）
  const strIdRes = await POST('/feedback/update-status', { feedbackId: 'abc', status: 1 });
  assert('feedbackId 为字符串不报500',
    strIdRes.code !== 500 || strIdRes.success === false,
    strIdRes);
}

// ────── 维度 9: 并发请求 ──────
async function testConcurrency() {
  console.log('\n🔀 9. 并发请求');

  // 5个并发 GET
  const promises = Array.from({ length: 5 }, (_, i) =>
    GET(`/feedback/list?pageNum=${i + 1}&pageSize=5`)
  );
  const results = await Promise.all(promises);
  const allOk = results.every(r => r.success === true);
  assert('5个并发 GET 请求都成功', allOk, results.map(r => r.success));

  // 并发提交反馈
  const submitPromises = Array.from({ length: 3 }, (_, i) => {
    const fd = new FormData();
    fd.append('data', new Blob([JSON.stringify({
      feedbackType: 'other',
      content: `【自动化测试】并发提交 #${i}`,
    })], { type: 'application/json' }));
    return POST('/feedback/submit', fd);
  });
  const submitResults = await Promise.all(submitPromises);
  const allSubmitOk = submitResults.every(r => r.success === true);
  assert('3个并发 submit 都成功', allSubmitOk, submitResults.map(r => r.success));

  // 记录并发提交的ID用于清理
  const checkList = await GET(`/feedback/list?keyword=${encodeURIComponent('【自动化测试】并发提交')}&pageNum=1&pageSize=10`);
  if (checkList.data?.records) {
    for (const r of checkList.data.records) {
      createdFeedbackIds.push(r.id);
    }
  }
}

// ────── 维度 10: 响应结构一致性 ──────
async function testResponseStructure() {
  console.log('\n📦 10. 响应结构一致性');

  const res = await GET('/feedback/list?pageNum=1&pageSize=5');
  assert('含 current', typeof res.data?.current === 'number', res.data?.current);
  assert('含 size', typeof res.data?.size === 'number', res.data?.size);
  assert('size 与请求一致', res.data?.size === 5, res.data?.size);
  assert('含 total', typeof res.data?.total === 'number', res.data?.total);
  assert('含 records', Array.isArray(res.data?.records), res.data?.records);
  assert('records.length <= size', res.data?.records?.length <= 5, res.data?.records?.length);

  // pages 字段
  if (res.data?.total != null && res.data?.size != null) {
    const expectedPages = Math.ceil(res.data.total / res.data.size) || 1;
    assert('pages 字段正确', res.data.pages === expectedPages || res.data.pages === 0,
      `pages=${res.data.pages}, expected=${expectedPages}`);
  }

  // 成功响应结构
  const submitFd = new FormData();
  submitFd.append('data', new Blob([JSON.stringify({
    feedbackType: 'feat',
    content: '【自动化测试】响应结构检查',
  })], { type: 'application/json' }));
  const submitRes = await POST('/feedback/submit', submitFd);
  assert('submit 返回含 success 字段', typeof submitRes.success === 'boolean', submitRes);
  assert('submit 返回含 code 字段', typeof submitRes.code === 'number', submitRes);

  // 记录清理
  const check = await GET(`/feedback/list?keyword=${encodeURIComponent('【自动化测试】响应结构检查')}&pageNum=1&pageSize=1`);
  if (check.data?.records?.[0]) createdFeedbackIds.push(check.data.records[0].id);
}

// ────── 维度 11: 多来源数据对比 ──────
async function testMultiSourceData() {
  console.log('\n📦 11. 多来源数据对比（站内 vs MM）');

  // 提交一条站内反馈
  const fd = new FormData();
  fd.append('data', new Blob([JSON.stringify({
    feedbackType: 'lag',
    content: '【自动化测试】来源对比-站内',
  })], { type: 'application/json' }));
  await POST('/feedback/submit', fd);

  // 提交一条 MM 反馈
  await POST('/feedback/syncMessage', {
    files: [],
    content: '【自动化测试】来源对比-MM',
    feedbackNickName: '来源对比测试',
    feedbackSource: 0,
    messageId: 'compare-test-' + Date.now(),
  });

  // 查询并对比
  const list = await GET(`/feedback/list?keyword=${encodeURIComponent('【自动化测试】来源对比')}&pageNum=1&pageSize=20`);
  const sentryItems = list.data?.records?.filter(r => r.source === 'sentry') || [];
  const mmItems = list.data?.records?.filter(r => r.source === 'mm') || [];
  assert('站内反馈 source=sentry', sentryItems.length > 0, sentryItems.length);
  assert('MM反馈 source=mm', mmItems.length > 0, mmItems.length);

  // 验证两种来源的字段结构一致
  if (sentryItems.length > 0 && mmItems.length > 0) {
    const sentryKeys = Object.keys(sentryItems[0]).sort();
    const mmKeys = Object.keys(mmItems[0]).sort();
    assert('两种来源字段结构一致', sentryKeys.join(',') === mmKeys.join(','),
      `sentry: ${sentryKeys.join(',')}\nmm: ${mmKeys.join(',')}`);
  }

  // 记录清理
  for (const r of (list.data?.records || [])) {
    createdFeedbackIds.push(r.id);
  }
}

// ────── 维度 12: 数据排序验证 ──────
async function testSorting() {
  console.log('\n📊 12. 数据排序验证');

  const list = await GET('/feedback/list?pageNum=1&pageSize=50');
  if (list.data?.records?.length >= 2) {
    // 验证按 feedbackTime 降序
    let isDescending = true;
    for (let i = 1; i < list.data.records.length; i++) {
      const prev = new Date(list.data.records[i - 1].feedbackTime);
      const curr = new Date(list.data.records[i].feedbackTime);
      if (prev < curr) {
        isDescending = false;
        break;
      }
    }
    assert('列表按 feedbackTime 降序排列', isDescending);
  } else {
    console.log('  ⚠️ 数据不足2条，跳过排序验证');
  }
}

// ────── 维度 13: 未登录访问 ──────
async function testUnloggedAccess() {
  console.log('\n🔒 13. 未登录访问 + 错误码规范性');

  saveSession('main');
  cookie = ''; // 清除登录状态

  // 未登录访问 list（需要登录的接口）
  const listRes = await rawFetch('GET', `${CONFIG.host}/api/v1/feedback/list?pageNum=1&pageSize=20`);
  assert('未登录 GET /list 不报500', listRes.status !== 500, listRes.status);

  // 未登录提交反馈
  const fd = new FormData();
  fd.append('data', new Blob([JSON.stringify({
