    restoreSession('main');
    const check = await GET(`/feedback/list?keyword=${encodeURIComponent('不需要登录')}&pageNum=1&pageSize=1`);
    if (check.data?.records?.[0]) createdFeedbackIds.push(check.data.records[0].id);
  }

  restoreSession('main');
}

