package com.yottastudios.ns.collabspace.shared.config.security;

import cn.hutool.core.util.StrUtil;
import com.yottastudios.ns.collabspace.shared.util.JwtUtil;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.List;
import lombok.extern.slf4j.Slf4j;
import org.jetbrains.annotations.NotNull;
import org.springframework.http.HttpHeaders;
import org.springframework.security.web.csrf.CsrfFilter;
import org.springframework.web.filter.OncePerRequestFilter;

/**
 * <p>
 * execute in front of csrf filter.
 * </p>
 *
 * @author Shawn Deng
 */
@Slf4j
public class CsrfBeforeFilter extends OncePerRequestFilter {

    public List<String> ignorePath = List.of("/mapper/base/attach/cite","/node/role/getAppNodesRole");

    @Override
    protected void doFilterInternal(HttpServletRequest request,
                                    @NotNull HttpServletResponse response,
                                    @NotNull FilterChain filterChain)
        throws ServletException, IOException {
        String bearerToken = request.getHeader(HttpHeaders.AUTHORIZATION);
        String jwtToken = JwtUtil.getJwtFromRequest(request);

        if (log.isDebugEnabled()) {
            log.info("csrf before filter path: {}", request.getServletPath());
        }

        if (StrUtil.isNotBlank(bearerToken) || 
            (StrUtil.isNotBlank(jwtToken) && JwtUtil.getUserIdAsLong(jwtToken) != null) ||
            this.ignorePath.contains(request.getServletPath())) {
            CsrfFilter.skipRequest(request);
        }
        filterChain.doFilter(request, response);
    }
}

